INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9e15c3b0-e0ae-407a-8614-2d68373c3157',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark 101: Passive Recon with dns.layers$escape$,
  $escape$When conducting passive reconnaissance, Wireshark's dns.layers can help identify the attack surface. To visualize DNS queries, go to "Analyze" > "Display Filters" and enter dns.layers. This will reveal DNS queries and their corresponding layers. Use the "Follow Stream" feature to inspect DNS packets and identify potential vulnerabilities. For example, if a DNS query is made to a non-standard port, it may indicate an open alternative DNS service.$escape$,
  NULL,
  NULL,
