INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8bab6827-9bd8-49b8-85c7-6db6451ddeb7',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark — Harnessing Nmap for Comprehensive Network Scans$escape$,
  $escape$To tap into Nmap's capabilities within Wireshark, navigate to Capture > Interfaces > Preferences. In the 'Capture Options' tab, select the 'Capture as' dropdown and choose 'Nmap' as the protocol. Next, configure your Nmap scan parameters, such as target IP, ports, and OS detection. You can also enable NSE (Nmap Scripting Engine) scripts for advanced discovery and exploitation. To view the captured data, switch to the 'Wireshark' protocol and analyze the packets.$escape$,
