INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4b525e39-ba95-49f9-b0be-ac46208d5fcc',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark - Uncovering Meterpreter Traffic with Metasploit$escape$,
  $escape$When analyzing network traffic with Wireshark, you may encounter encrypted communications from the Meterpreter payload, a key component of the Metasploit framework. Meterpreter uses a dynamic protocol (DP) to establish a secure connection with the attacker's control server. To decode Meterpreter traffic, navigate to 'Edit' > 'Preferences' > 'Protocols' and enable 'Metasploit' protocol. This will allow you to decode Meterpreter commands and responses. You can also use the 'Follow Stream' functionality to analyze the decrypted data. Additionally, you can use the 'Apply As Filter' feature to isolate Meterpreter traffic and analyze it further.$escape$,
  NULL,
  NULL,
