INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bd09486b-96a9-434a-8dc4-72f85f36aa32',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark Network Scanning — Uncovering Hidden Services$escape$,
  $escape$To perform subnet scanning and service enumeration in Wireshark, select Capture > Start and navigate to Capture Options. Under the Interface tab, ensure the correct interface is selected. Then, click the Options button next to the Interface dropdown. In the Extended Options dialog, navigate to the UDP and TCP tabs and enable the 'Scan for' options. This will enable subnet scanning. Next, use the 'Follow TCP Stream' feature to examine the TCP handshake and identify services. You can also use the 'Follow HTTP Stream' feature to capture HTTP requests and analyze them. To grab banners, right-click the packet and select 'Follow SSL Stream' or 'Follow TCP Stream'. Wireshark will display the SSL or TCP handshake, allowing you to extract the banner.$escape$,
  NULL,
  NULL,
