INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8b5c0bf0-73ff-458d-9d26-e1b645472875',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark — Uncovering WPA2 Evil Twin Attacks with eapol_dissect$escape$,
  $escape$When performing wireless security assessments with Wireshark, it's essential to detect WPA2 evil twin attacks. These attacks involve a rogue Access Point (AP) mimicking a legitimate one, tricking clients into connecting to it. To identify such attacks, use the eapol_dissect feature. In Wireshark, go to Edit > Preferences > Protocols > IEEE 802.11, and check "Enable EAPOL dissector". Then, in the Capture Filter field, enter "eapol" to display EAPOL packets. Analyze the "Client Response" field to spot the rogue AP's MAC address. Use the "Follow Stream" feature to examine the entire packet and look for inconsistencies in the client's response.$escape$,
  NULL,
  NULL,
