INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '62da9684-2785-427e-8176-6c0459e2e590',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark - Mastering Responsible Disclosure with Scope Reading$escape$,
  $escape$When discovering vulnerabilities during bug bounty hunting with Wireshark, it's essential to follow responsible disclosure practices. This involves identifying the affected scope, which can be a specific network segment or device. You can use Wireshark's capture filter syntax to define the scope. For example, `ip.src_host == 192.168.1.100` captures all packets originating from the host with IP address `192.168.1.100`. To avoid duplicate reports, keep a record of the submitted bugs and use Wireshark's unique packet IDs to verify whether a vulnerability has already been reported. Use the `Sequence Number` column in the packet list view to identify duplicate packets.$escape$,
  NULL,
  NULL,
