INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '56024a29-791c-43f1-94c9-a62465279dfc',
  '00000000-0000-0000-0000-000000000001',
  $escape$Wireshark - Red Team vs Pentest: Stealthy Packet Capture$escape$,
  $escape$Red Teams employ stealthy packet capture techniques to evade detection, unlike traditional pentesting methods. In Wireshark, this translates to using the 'Capture Options' > 'Promiscuous Mode' setting to capture all packets, not just those destined for the machine running Wireshark. Red Teams also leverage Wireshark's 'Follow Stream' feature to analyze encrypted traffic without decrypting the entire capture file. In contrast, pentesters typically focus on exploiting vulnerabilities and achieving persistence, which may not require stealthy packet capture. When analyzing packet captures, use the 'Statistics' > 'Protocol Hierarchy' view to identify potential security threats.$escape$,
  NULL,
  NULL,
